//  The Lego Blocks (Behaviors)
const canFly = { fly() { console.log('Flying in the sky!'); } };
const canSwim = { swim() { console.log('Swimming in the water!'); } };

// ️ The Factory
function createDuck(name) {
  const duck = { name };
  // Compose the duck by merging the behaviors together!
  return Object.assign(duck, canFly, canSwim);
}

const daffy = createDuck('Daffy');
daffy.fly();  // Works!
daffy.swim(); // Works! 
// We built a duck without a single 'class' or 'extends' keyword.

